(() => {
  // ============ DATA SETUP ============
  const PROGS = window.DASA_PROGRAMS || [];
  const INSTITUTES = window.DASA_INSTITUTES || {};

  // ---- normaliseName for India GeoJSON
  function normaliseName(raw) {
    const map = {
      "Orissa": "Odisha", "Pondicherry": "Puducherry",
      "Uttaranchal": "Uttarakhand", "Telengana": "Telangana",
      "NCT of Delhi": "Delhi", "Delhi (NCT)": "Delhi",
      "Jammu & Kashmir": "Jammu and Kashmir",
      "Jammu And Kashmir": "Jammu and Kashmir",
      "Andaman & Nicobar Islands": "Andaman and Nicobar Islands",
      "Andaman & Nicobar Island": "Andaman and Nicobar Islands",
      "Dadra and Nagar Haveli": "Dadra and Nagar Haveli and Daman and Diu",
      "Daman and Diu": "Dadra and Nagar Haveli and Daman and Diu"
    };
    return map[(raw || "").trim()] || (raw || "").trim();
  }

  // build state -> count + state -> programs index
  const STATE_COUNTS = {};
  const STATE_PROGS = {};
  const STATE_INSTS = {};
  PROGS.forEach(p => {
    if (!p.s || p.s === 'Unknown') return;
    STATE_COUNTS[p.s] = (STATE_COUNTS[p.s] || 0) + 1;
    (STATE_PROGS[p.s] = STATE_PROGS[p.s] || []).push(p);
    (STATE_INSTS[p.s] = STATE_INSTS[p.s] || new Set()).add(p.i);
  });
  // convert sets to arrays
  Object.keys(STATE_INSTS).forEach(s => STATE_INSTS[s] = Array.from(STATE_INSTS[s]));

  // counts by type
  const TYPE_COUNTS = { NIT: 0, IIIT: 0, SPA: 0, State: 0, Private: 0, Other: 0 };
  Object.values(INSTITUTES).forEach(m => { if (TYPE_COUNTS[m.tag] !== undefined) TYPE_COUNTS[m.tag]++; });

  // ---- color ramp
  const RAMP = ["#FBF7EE", "#E8DFC8", "#B7C2DC", "#7B91C2", "#3D5DA3", "#0E3A8A"];
  function colorFor(value, max) {
    if (!value || max === 0) return RAMP[0];
    const r = value / max;
    if (r < 0.04) return RAMP[1];
    if (r < 0.12) return RAMP[2];
    if (r < 0.28) return RAMP[3];
    if (r < 0.60) return RAMP[4];
    return RAMP[5];
  }

  // ---- GeoJSON loading with fallback
  const GEO_SOURCES = [
    "https://cdn.jsdelivr.net/gh/udit-001/india-maps-data@ef25ebc/geojson/india.geojson",
    "https://cdn.jsdelivr.net/gh/udit-001/india-maps-data@main/geojson/india.geojson"
  ];
  const loadGeo = () => GEO_SOURCES.reduce((p, url) => p.catch(() => d3.json(url)), Promise.reject());

  // ============ MAP STATE ============
  let currentFilter = { quota: 'all', tag: null }; // map filter
  let selectedState = null;
  let projection, path;
  let svg, statesLayer, pinsLayer;
  let geoData;

  // Init type-count badges
  document.getElementById('b-nit').textContent = TYPE_COUNTS.NIT;
  document.getElementById('b-iiit').textContent = TYPE_COUNTS.IIIT;
  document.getElementById('b-spa').textContent = TYPE_COUNTS.SPA;
  document.getElementById('b-other').textContent = TYPE_COUNTS.State + TYPE_COUNTS.Other + TYPE_COUNTS.Private;

  // ---- compute filtered state counts based on current filter
  function computeStateCounts() {
    const counts = {};
    PROGS.forEach(p => {
      if (!p.s || p.s === 'Unknown') return;
      if (currentFilter.quota !== 'all' && p.q !== currentFilter.quota) return;
      if (currentFilter.tag) {
        const meta = INSTITUTES[p.i];
        const isOther = currentFilter.tag === 'State' && (meta && (meta.tag === 'Other' || meta.tag === 'Private'));
        if (meta && meta.tag !== currentFilter.tag && !isOther) return;
        if (!meta) return;
      }
      counts[p.s] = (counts[p.s] || 0) + 1;
    });
    return counts;
  }

  function shouldShowPins() {
    return !!currentFilter.tag;
  }

  function buildPinList() {
    if (!shouldShowPins()) return [];
    const seen = new Set();
    const pins = [];
    Object.entries(INSTITUTES).forEach(([name, m]) => {
      if (!m.lat || !m.lng) return;
      const wantTag = currentFilter.tag;
      const isOther = wantTag === 'State' && (m.tag === 'Other' || m.tag === 'Private' || m.tag === 'State');
      if (m.tag !== wantTag && !isOther) return;

      // also restrict by quota filter
      if (currentFilter.quota !== 'all') {
        const hasMatch = PROGS.some(p => p.i === name && p.q === currentFilter.quota);
        if (!hasMatch) return;
      }
      if (seen.has(name)) return;
      seen.add(name);
      pins.push({ name, ...m });
    });
    return pins;
  }

  function renderMap() {
    if (!geoData || !svg) return;
    const counts = computeStateCounts();
    const max = Math.max(...Object.values(counts), 1);
    const showPins = shouldShowPins();

    // states
    statesLayer.selectAll("path.state")
      .transition().duration(300)
      .attr("fill", d => {
        const name = normaliseName(d.properties.st_nm);
        const v = counts[name] || 0;
        if (showPins) {
          // soft tint
          return v > 0 ? '#F0E5D0' : RAMP[0];
        }
        return colorFor(v, max);
      });

    // pins
    const pinData = buildPinList();
    const pins = pinsLayer.selectAll("circle.pin").data(pinData, d => d.name);
    pins.exit().transition().duration(220).attr("r", 0).remove();
    const enter = pins.enter().append("circle")
      .attr("class", "pin")
      .attr("cx", d => projection([d.lng, d.lat])[0])
      .attr("cy", d => projection([d.lng, d.lat])[1])
      .attr("r", 0)
      .on("mousemove", function(event, d) {
        const ct = PROGS.filter(p => p.i === d.name && (currentFilter.quota === 'all' || p.q === currentFilter.quota)).length;
        showTooltip(event, `
          <span class="tt-name">${d.name}</span>
          <span class="tt-meta">${d.city || ''} · ${d.s} · ${d.tag}</span>
          <span class="tt-data"><b>${ct}</b> program${ct===1?'':'s'} listed${currentFilter.quota !== 'all' ? ' ('+currentFilter.quota+')' : ''}</span>
        `);
        d3.select(this).attr("r", 9);
      })
      .on("mouseleave", function() { hideTooltip(); d3.select(this).attr("r", 5.5); })
      .on("click", function(event, d) { selectState(d.s); });
    enter.transition().duration(420).delay((d, i) => i * 18).attr("r", 5.5);

    // Update card subtitle
    const sub = showPins
      ? `Pins · ${pinData.length} ${currentFilter.tag === 'State' ? 'state / other' : currentFilter.tag} campus${pinData.length===1?'':'es'}`
      : `Choropleth · institutes per state${currentFilter.quota !== 'all' ? ' · '+currentFilter.quota : ''}`;
    document.getElementById('mapSubtitle').textContent = sub;
  }

  // ---- Tooltip helpers
  const tooltipEl = document.getElementById('mapTooltip');
  function showTooltip(event, html) {
    tooltipEl.innerHTML = html;
    tooltipEl.style.left = (event.clientX + 14) + 'px';
    tooltipEl.style.top = (event.clientY + 14) + 'px';
    tooltipEl.classList.add('visible');
    tooltipEl.setAttribute('aria-hidden', 'false');
    // boundary check
    const r = tooltipEl.getBoundingClientRect();
    if (r.right > window.innerWidth) tooltipEl.style.left = (event.clientX - r.width - 14) + 'px';
    if (r.bottom > window.innerHeight) tooltipEl.style.top = (event.clientY - r.height - 14) + 'px';
  }
  function hideTooltip() {
    tooltipEl.classList.remove('visible');
    tooltipEl.setAttribute('aria-hidden', 'true');
  }

  // ============ RIGHT PANEL: TOP STATES / DRILL DOWN ============
  const rightPanel = document.getElementById('rightPanel');
  const panelBody = document.getElementById('panelBody');
  const instSel = document.getElementById('instSel');

  // Populate institute dropdown — grouped by tag
  (function populateInstSel() {
    const groups = {};
    Object.keys(INSTITUTES).forEach(name => {
      const tag = INSTITUTES[name].tag || 'Other';
      if (!groups[tag]) groups[tag] = [];
      groups[tag].push(name);
    });
    const order = ['NIT','IIIT','SPA','State','Private','Other'];
    order.forEach(tag => {
      if (!groups[tag]) return;
      const og = document.createElement('optgroup');
      og.label = tag === 'State' ? 'State / Deemed' : (tag + (tag === 'Other' ? '' : 's'));
      groups[tag].sort().forEach(name => {
        const opt = document.createElement('option');
        opt.value = name;
        opt.textContent = name;
        og.appendChild(opt);
      });
      instSel.appendChild(og);
    });
  })();

  instSel.addEventListener('change', e => {
    const v = e.target.value;
    if (v) {
      renderInstituteDetail(v);
    } else if (selectedState) {
      renderStateDetail(selectedState);
    } else {
      renderTopStates();
    }
  });

  // Clear button for institute filter
  const instClearBtn = document.getElementById('instClear');
  if (instClearBtn) {
    instClearBtn.addEventListener('click', () => {
      instSel.value = '';
      if (selectedState) {
        renderStateDetail(selectedState);
      } else {
        renderTopStates();
      }
    });
  }

  function renderTopStates() {
    const counts = computeStateCounts();
    const max = Math.max(...Object.values(counts), 1);
    const entries = Object.entries(counts).sort((a,b) => b[1]-a[1]).slice(0, 10);
    let html = `
      <div class="panel-card-header">
        <div>
          <div class="panel-card-title">Top states · DASA presence</div>
          <div class="panel-card-note">Click any state to drill in</div>
        </div>
      </div>
      <ol class="ranked-list">`;
    entries.forEach(([state, val], i) => {
      const pct = Math.round((val / max) * 100);
      html += `<li>
        <span class="rl-rank">${String(i+1).padStart(2,'0')}</span>
        <span class="rl-name" style="--bar-w:${pct}%;">${state}</span>
        <span class="rl-val">${val}</span>
      </li>`;
    });
    html += `</ol>
      <div class="drill-section-title">Pro tip</div>
      <p style="font-size:13.5px; color:var(--muted); margin: 8px 0 0; line-height:1.5;">
        Filter by <b>CIWG</b> or <b>Non-CIWG</b> above to see how the seat distribution shifts. Tap a state on the map or pick an institute above to drill in.
      </p>`;
    panelBody.innerHTML = html;
  }

  function selectState(state) {
    if (!STATE_PROGS[state]) return;
    selectedState = state;
    d3.selectAll("#india-map path.state").classed("selected", false);
    d3.selectAll("#india-map path.state").each(function(d) {
      if (normaliseName(d.properties.st_nm) === state) d3.select(this).classed("selected", true);
    });
    renderStateDetail(state);
  }

  function clearSelection() {
    selectedState = null;
    d3.selectAll("#india-map path.state").classed("selected", false);
    renderTopStates();
  }

  function renderStateDetail(state) {
    const allProgs = STATE_PROGS[state] || [];
    let progs = allProgs;
    if (currentFilter.quota !== 'all') progs = progs.filter(p => p.q === currentFilter.quota);
    const insts = Array.from(new Set(progs.map(p => p.i)));
    const ciwgCount = progs.filter(p => p.q === 'CIWG').length;
    const nonCount = progs.filter(p => p.q === 'NONCIWG').length;

    // Top 5 programs in this state by closing rank
    const sorted = progs.filter(p => p.c).sort((a,b) => a.c - b.c).slice(0, 6);

    let html = `
      <div class="drill-header">
        <div class="drill-title"><small>State · drill-down</small>${state}</div>
        <button class="drill-back" onclick="window.__clearSel()">India view</button>
      </div>
      <div class="drill-stats">
        <div class="drill-stat"><div class="ds-num">${insts.length}<span>.</span></div><div class="ds-label">Institutes</div></div>
        <div class="drill-stat"><div class="ds-num">${progs.length}<span>.</span></div><div class="ds-label">Programs</div></div>
        <div class="drill-stat"><div class="ds-num">${ciwgCount}<span>.</span></div><div class="ds-label">CIWG seats</div></div>
        <div class="drill-stat"><div class="ds-num">${nonCount}<span>.</span></div><div class="ds-label">Non-CIWG seats</div></div>
      </div>
      <div class="drill-section-title">Institutes in ${state}</div>
      <ul class="college-list">`;
    insts.forEach(name => {
      const meta = INSTITUTES[name] || {};
      const ct = progs.filter(p => p.i === name).length;
      html += `<li>
        <span class="cl-name">${name}</span>
        <span class="cl-meta">${meta.tag || ''} · ${ct} prog${ct===1?'':'s'}</span>
      </li>`;
    });
    if (insts.length === 0) html += `<li class="cl-name" style="color:var(--muted);">No DASA institutes in this state.</li>`;
    html += `</ul>`;

    if (sorted.length > 0) {
      html += `<div class="drill-section-title">Lowest closing ranks (most competitive)</div>
        <ul class="college-list">`;
      sorted.forEach(p => {
        html += `<li>
          <span class="cl-name">${p.pn}<br><span style="font-weight:400; font-size:12px; color:var(--muted);">${p.i}</span></span>
          <span class="cl-meta">O ${formatNum(p.o)} · C ${formatNum(p.c)}</span>
        </li>`;
      });
      html += `</ul>`;
    }

    panelBody.innerHTML = html;
  }

  function formatNum(n) {
    if (n == null || isNaN(n)) return '—';
    return Number(n).toLocaleString('en-IN');
  }

  window.__clearSel = clearSelection;

  // ============ MAP INIT ============
  function initMap() {
    svg = d3.select("#india-map");
    statesLayer = svg.select(".states-layer");
    pinsLayer = svg.select(".pins-layer");

    loadGeo().then(geo => {
      geoData = geo;
      projection = d3.geoMercator().fitSize([720, 720], geo);
      path = d3.geoPath().projection(projection);

      statesLayer.selectAll("path.state")
        .data(geo.features)
        .enter()
        .append("path")
        .attr("class", "state")
        .attr("d", path)
        .attr("fill", RAMP[0])
        .on("mousemove", function(event, d) {
          const name = normaliseName(d.properties.st_nm);
          const counts = computeStateCounts();
          const v = counts[name] || 0;
          if (v > 0) {
            const insts = (STATE_INSTS[name] || []).length;
            showTooltip(event, `
              <span class="tt-name">${name}</span>
              <span class="tt-meta">Click to drill in</span>
              <span class="tt-data"><b>${insts}</b> institute${insts===1?'':'s'} · <b>${v}</b> program${v===1?'':'s'}</span>
            `);
          } else {
            showTooltip(event, `
              <span class="tt-name">${name}</span>
              <span class="tt-data">No DASA institutes in current filter</span>
            `);
          }
        })
        .on("mouseleave", hideTooltip)
        .on("click", function(event, d) {
          const name = normaliseName(d.properties.st_nm);
          if (STATE_PROGS[name]) selectState(name);
        });

      renderMap();
      renderTopStates();
    }).catch(err => {
      console.error('Map load failed', err);
      document.getElementById('mapSubtitle').textContent = 'Could not load map — please refresh';
    });
  }

  // ============ FILTER BAR ============
  function setupFilterBar() {
    const pills = document.querySelectorAll('.filter-bar .filter-pill');
    pills.forEach(p => {
      p.addEventListener('click', () => {
        const isQuota = p.hasAttribute('data-filter');
        const isTag = p.hasAttribute('data-tag');

        if (isQuota) {
          pills.forEach(q => { if (q.hasAttribute('data-filter')) q.setAttribute('aria-pressed', q === p ? 'true' : 'false'); });
          currentFilter.quota = p.dataset.filter;
        }
        if (isTag) {
          const pressed = p.getAttribute('aria-pressed') === 'true';
          pills.forEach(q => { if (q.hasAttribute('data-tag')) q.setAttribute('aria-pressed', 'false'); });
          if (!pressed) {
            p.setAttribute('aria-pressed', 'true');
            currentFilter.tag = p.dataset.tag;
          } else {
            currentFilter.tag = null;
          }
        }
        renderMap();
        if (selectedState) renderStateDetail(selectedState); else renderTopStates();
      });
    });
  }

  // ============ DATABASE TABLE ============
  let dbState = { search: '', state: '', quota: '', sort: 'c-asc', page: 0 };
  const PAGE_SIZE = 25;

  function setupDatabase() {
    // populate state filter
    const states = Array.from(new Set(PROGS.map(p => p.s).filter(s => s && s !== 'Unknown'))).sort();
    const sel = document.getElementById('dbState');
    states.forEach(s => {
      const o = document.createElement('option');
      o.value = s; o.textContent = s;
      sel.appendChild(o);
    });

    document.getElementById('dbSearch').addEventListener('input', e => { dbState.search = e.target.value.toLowerCase(); dbState.page = 0; renderDB(); });
    document.getElementById('dbState').addEventListener('change', e => { dbState.state = e.target.value; dbState.page = 0; renderDB(); });
    document.getElementById('dbQuota').addEventListener('change', e => { dbState.quota = e.target.value; dbState.page = 0; renderDB(); });
    document.getElementById('dbSort').addEventListener('change', e => { dbState.sort = e.target.value; renderDB(); });
    document.getElementById('pgPrev').addEventListener('click', () => { if (dbState.page > 0) { dbState.page--; renderDB(); } });
    document.getElementById('pgNext').addEventListener('click', () => {
      const filtered = filterDB();
      if ((dbState.page + 1) * PAGE_SIZE < filtered.length) { dbState.page++; renderDB(); }
    });

    renderDB();
  }

  function filterDB() {
    let arr = PROGS.slice();
    if (dbState.search) {
      const q = dbState.search;
      arr = arr.filter(p =>
        (p.i || '').toLowerCase().includes(q) ||
        (p.pn || '').toLowerCase().includes(q) ||
        (p.s || '').toLowerCase().includes(q)
      );
    }
    if (dbState.state) arr = arr.filter(p => p.s === dbState.state);
    if (dbState.quota) arr = arr.filter(p => p.q === dbState.quota);

    const sortMap = {
      'c-asc': (a,b) => (a.c ?? 1e15) - (b.c ?? 1e15),
      'c-desc': (a,b) => (b.c ?? 0) - (a.c ?? 0),
      'o-asc': (a,b) => (a.o ?? 1e15) - (b.o ?? 1e15),
      'i-asc': (a,b) => (a.i || '').localeCompare(b.i || ''),
      'p-asc': (a,b) => (a.pn || '').localeCompare(b.pn || ''),
    };
    arr.sort(sortMap[dbState.sort] || sortMap['c-asc']);
    return arr;
  }

  function renderDB() {
    const filtered = filterDB();
    document.getElementById('dbCount').textContent = filtered.length;
    const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
    if (dbState.page >= totalPages) dbState.page = totalPages - 1;
    const slice = filtered.slice(dbState.page * PAGE_SIZE, (dbState.page + 1) * PAGE_SIZE);

    const body = document.getElementById('dbBody');
    body.innerHTML = slice.map(p => `
      <tr>
        <td class="col-inst">${p.i}<br><span style="font-family:'JetBrains Mono',monospace; font-size:10px; letter-spacing:.15em; text-transform:uppercase; color:var(--muted); font-weight:500;">${p.s}</span></td>
        <td class="col-prog">${p.pn}${p.dur ? ' <span class="inline-tag">'+p.dur+'Y</span>' : ''}</td>
        <td><span class="inline-tag ${p.q === 'CIWG' ? 'tag-orange' : ''}">${p.q === 'CIWG' ? 'CIWG' : 'Non-CIWG'}</span></td>
        <td class="col-rank">${formatNum(p.o)}</td>
        <td class="col-rank">${formatNum(p.c)}</td>
        <td class="col-rank">${p.r}</td>
      </tr>
    `).join('') || `<tr><td colspan="6" style="text-align:center; padding:40px; color:var(--muted);">No programs match these filters.</td></tr>`;

    document.getElementById('pgInfo').textContent = `Page ${dbState.page + 1} of ${totalPages}`;
    document.getElementById('pgPrev').disabled = dbState.page === 0;
    document.getElementById('pgNext').disabled = (dbState.page + 1) >= totalPages;
    document.getElementById('dbPageMeta').textContent = `Showing ${slice.length ? dbState.page*PAGE_SIZE + 1 : 0}–${dbState.page*PAGE_SIZE + slice.length}`;
  }

  // ============ CHARTS ============
  function setupCharts() {
    if (typeof Chart === 'undefined') return;

    Chart.defaults.font.family = "'Plus Jakarta Sans', sans-serif";
    Chart.defaults.color = '#5A6278';
    Chart.defaults.borderColor = '#E8DFC8';

    // 1. by institute type, stacked by quota
    const types = ['NIT', 'IIIT', 'SPA', 'State', 'Other', 'Private'];
    const ciwgByType = types.map(t => PROGS.filter(p => {
      const m = INSTITUTES[p.i];
      return m && m.tag === t && p.q === 'CIWG';
    }).length);
    const nonByType = types.map(t => PROGS.filter(p => {
      const m = INSTITUTES[p.i];
      return m && m.tag === t && p.q === 'NONCIWG';
    }).length);

    new Chart(document.getElementById('chartType'), {
      type: 'bar',
      data: {
        labels: ['NIT', 'IIIT', 'SPA', 'State', 'Other', 'Private'],
        datasets: [
          { label: 'CIWG', data: ciwgByType, backgroundColor: '#FF6B0A', borderRadius: 6 },
          { label: 'Non-CIWG', data: nonByType, backgroundColor: '#0E3A8A', borderRadius: 6 }
        ]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { position: 'bottom', labels: { boxWidth: 12, padding: 16, font: { size: 12, weight: '500' } } },
          tooltip: { backgroundColor: '#071A44', titleFont: { size: 13, weight: '600' }, bodyFont: { size: 12 }, padding: 10 }
        },
        scales: {
          x: { stacked: false, grid: { display: false }, ticks: { font: { weight: '600' } } },
          y: { beginAtZero: true, grid: { color: '#E8DFC8', drawBorder: false }, ticks: { precision: 0 } }
        }
      }
    });

    // 2. by round
    const rounds = ['R1', 'R1, R2', 'R1, R2, R3'];
    const roundData = rounds.map(r => PROGS.filter(p => p.r === r).length);
    new Chart(document.getElementById('chartRound'), {
      type: 'doughnut',
      data: {
        labels: ['R1 only', 'R1 + R2', 'R1 + R2 + R3'],
        datasets: [{
          data: roundData,
          backgroundColor: ['#0E3A8A', '#3D5DA3', '#FF6B0A'],
          borderColor: '#FFFDF7', borderWidth: 3
        }]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        cutout: '60%',
        plugins: {
          legend: { position: 'bottom', labels: { boxWidth: 12, padding: 14, font: { size: 12, weight: '500' } } },
          tooltip: { backgroundColor: '#071A44', padding: 10 }
        }
      }
    });

    // 3. Top 10 competitive branches CIWG
    const ciwgPool = PROGS.filter(p => p.q === 'CIWG' && p.c);
    const byBranch = {};
    ciwgPool.forEach(p => {
      if (!byBranch[p.pn] || p.o < byBranch[p.pn].o) byBranch[p.pn] = { o: p.o, c: p.c };
    });
    const top10 = Object.entries(byBranch)
      .map(([pn, v]) => ({ pn, ...v }))
      .sort((a, b) => a.o - b.o)
      .slice(0, 10);

    new Chart(document.getElementById('chartBranch'), {
      type: 'bar',
      data: {
        labels: top10.map(t => t.pn.length > 36 ? t.pn.slice(0, 36) + '…' : t.pn),
        datasets: [
          { label: 'Best opening rank', data: top10.map(t => t.o), backgroundColor: '#FF6B0A', borderRadius: 4, barThickness: 14 },
          { label: 'Best closing rank', data: top10.map(t => t.c), backgroundColor: '#0E3A8A', borderRadius: 4, barThickness: 14 }
        ]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        indexAxis: 'y',
        plugins: {
          legend: { position: 'bottom', labels: { boxWidth: 12, padding: 14, font: { size: 12, weight: '500' } } },
          tooltip: { backgroundColor: '#071A44', padding: 10 }
        },
        scales: {
          x: { beginAtZero: true, grid: { color: '#E8DFC8' }, ticks: { callback: v => v >= 1000 ? (v/1000).toFixed(0)+'k' : v } },
          y: { grid: { display: false }, ticks: { font: { size: 11 } } }
        }
      }
    });
  }

  // ============ FAQ ACCORDION ============
  function setupFAQ() {
    document.querySelectorAll('[data-faq]').forEach(item => {
      item.addEventListener('click', () => {
        const open = item.classList.contains('open');
        document.querySelectorAll('[data-faq]').forEach(i => i.classList.remove('open'));
        if (!open) item.classList.add('open');
      });
    });
  }

  // ============ MOBILE MENU ============
  function setupMobileMenu() {
    const btn = document.getElementById('hamburger');
    const menu = document.getElementById('mobileMenu');
    btn.addEventListener('click', () => {
      const isOpen = menu.classList.toggle('open');
      btn.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
    });
    menu.querySelectorAll('a').forEach(a => a.addEventListener('click', () => {
      menu.classList.remove('open');
      btn.setAttribute('aria-expanded', 'false');
    }));
  }

  // ============ SCROLL REVEAL ============
  function setupReveal() {
    const io = new IntersectionObserver(entries => {
      entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); io.unobserve(e.target); } });
    }, { threshold: 0.08, rootMargin: '0px 0px -40px 0px' });
    document.querySelectorAll('.reveal').forEach(el => io.observe(el));
  }

  // ============ BOOT ============
  document.addEventListener('DOMContentLoaded', () => {
    setupReveal();
    setupMobileMenu();
    setupFilterBar();
    initMap();
    setupDatabase();
    setupCharts();
    setupFAQ();
    setupNIRF();
  });

  // ============ NIRF RANKINGS TABLE ============
  function setupNIRF() {
    const DATA = window.NIRF_DASA || [];
    if (!DATA.length) return;

    const tbody = document.getElementById('nirfBody');
    const quotaSel = document.getElementById('nirfQuota');
    const sortSel = document.getElementById('nirfSort');
    const searchInp = document.getElementById('nirfSearch');
    const metaEl = document.getElementById('nirfMeta');
    const headers = document.querySelectorAll('#nirfTable thead th[data-sort]');
    if (!tbody) return;

    // current sort spec: {key, dir}
    let state = { sort: 'rank-asc', quota: 'all', search: '' };

    // map sort keys -> comparator factory
    const SORT_KEYS = {
      'rank':         (a,b) => (a.r === 999 ? Infinity : a.r) - (b.r === 999 ? Infinity : b.r),
      'rank-asc':     (a,b) => (a.r === 999 ? Infinity : a.r) - (b.r === 999 ? Infinity : b.r),
      'rank-desc':    (a,b) => (b.r === 999 ? -1 : b.r) - (a.r === 999 ? -1 : a.r),
      'score':        (a,b) => (b.sc ?? -1) - (a.sc ?? -1),
      'score-desc':   (a,b) => (b.sc ?? -1) - (a.sc ?? -1),
      'best-ciwg':    (a,b) => (a.bcc ?? Infinity) - (b.bcc ?? Infinity),
      'best-noncw':   (a,b) => (a.bnc ?? Infinity) - (b.bnc ?? Infinity),
      'ciwg':         (a,b) => (b.cc ?? 0) - (a.cc ?? 0),
      'ciwg-count':   (a,b) => (b.cc ?? 0) - (a.cc ?? 0),
      'noncw':        (a,b) => (b.nc ?? 0) - (a.nc ?? 0),
      'noncw-count':  (a,b) => (b.nc ?? 0) - (a.nc ?? 0),
      'name':         (a,b) => a.n.localeCompare(b.n),
    };

    // tag lookup from existing INSTITUTES table
    function tagFor(name) {
      const inst = INSTITUTES[name];
      return inst && inst.tag ? inst.tag : null;
    }

    function locFor(d) {
      const inst = INSTITUTES[d.n];
      const city = d.c || (inst && inst.city) || '';
      const state = d.s || (inst && inst.s) || '';
      return [city, state].filter(Boolean).join(' · ');
    }

    function fmtRank(v) {
      if (v === null || v === undefined) return '<span class="nirf-dash">—</span>';
      return v.toLocaleString('en-IN');
    }

    function fmtCount(v) {
      if (!v) return '<span class="nirf-dash">—</span>';
      return `<span class="nirf-count">${v}</span>`;
    }

    function rowHtml(d) {
      const tag = tagFor(d.n);
      const tagCls = tag ? tag.toLowerCase() : '';
      const tagHtml = tag ? `<span class="nirf-tag ${tagCls}">${tag === 'State' ? 'State / Other' : tag}</span>` : '';
      const rankCell = d.r === 999
        ? `<span class="unranked">Unranked</span>`
        : `#${d.r}`;
      const scoreCell = d.sc != null
        ? `<span class="nirf-score-pill">${d.sc.toFixed(2)}</span>`
        : `<span class="nirf-score-empty">N/A</span>`;
      const bestCiwg = d.bcc != null
        ? `<div class="nirf-rank-num">${fmtRank(d.bcc)}</div><div class="nirf-rank-sub">JEE AIR · best 2025</div>`
        : `<span class="nirf-dash">—</span>`;
      const bestNon = d.bnc != null
        ? `<div class="nirf-rank-num">${fmtRank(d.bnc)}</div><div class="nirf-rank-sub">JEE AIR · best 2025</div>`
        : `<span class="nirf-dash">—</span>`;
      return `
        <tr>
          <td class="nirf-rank-cell" data-label="NIRF Rank">${rankCell}</td>
          <td data-label="Institute">
            <div class="nirf-inst-name">${d.n}</div>
            <div class="nirf-inst-loc">${tagHtml}${locFor(d) || ''}</div>
          </td>
          <td data-label="NIRF Score">${scoreCell}</td>
          <td data-label="CIWG programs">${fmtCount(d.cc)}</td>
          <td data-label="Best CIWG closing">${bestCiwg}</td>
          <td data-label="Non-CIWG programs">${fmtCount(d.nc)}</td>
          <td data-label="Best Non-CIWG closing">${bestNon}</td>
        </tr>`;
    }

    function applyFilters() {
      const q = state.search.trim().toLowerCase();
      return DATA.filter(d => {
        if (state.quota === 'ciwg' && (!d.cc || d.cc === 0)) return false;
        if (state.quota === 'noncw' && (!d.nc || d.nc === 0)) return false;
        if (q) {
          const hay = (d.n + ' ' + (d.c || '') + ' ' + (d.s || '') + ' ' + locFor(d)).toLowerCase();
          if (!hay.includes(q)) return false;
        }
        return true;
      });
    }

    function render() {
      const rows = applyFilters();
      const cmp = SORT_KEYS[state.sort] || SORT_KEYS['rank-asc'];
      rows.sort(cmp);

      if (!rows.length) {
        tbody.innerHTML = `
          <tr><td colspan="7">
            <div class="nirf-empty">
              <h4>No institutes match</h4>
              <p>Try clearing the search or switching the quota filter.</p>
            </div>
          </td></tr>`;
      } else {
        tbody.innerHTML = rows.map(rowHtml).join('');
      }

      if (metaEl) {
        const total = DATA.length;
        const showing = rows.length;
        metaEl.textContent = showing === total
          ? `${total} institutes`
          : `${showing} of ${total} institutes`;
      }

      // update sort indicators on header cells
      headers.forEach(h => {
        h.removeAttribute('data-active');
        const ind = h.querySelector('.sort-ind');
        if (ind) ind.textContent = '';
      });
      const baseKey = state.sort.replace(/-asc|-desc/, '');
      const activeHeader = Array.from(headers).find(h => h.dataset.sort === baseKey || h.dataset.sort === state.sort);
      if (activeHeader) {
        activeHeader.setAttribute('data-active', 'true');
        const ind = activeHeader.querySelector('.sort-ind');
        if (ind) {
          // direction arrow
          const asc = state.sort === 'rank-asc' || state.sort === 'name';
          ind.textContent = asc ? '▲' : '▼';
        }
      }
    }

    // Wire controls
    if (quotaSel) quotaSel.addEventListener('change', e => { state.quota = e.target.value; render(); });
    if (sortSel) sortSel.addEventListener('change', e => { state.sort = e.target.value; render(); });
    if (searchInp) searchInp.addEventListener('input', e => { state.search = e.target.value; render(); });

    // Clickable column headers
    headers.forEach(h => {
      h.addEventListener('click', () => {
        const key = h.dataset.sort;
        if (!key) return;
        // toggle direction if same key
        const base = state.sort.replace(/-asc|-desc/, '');
        if (key === 'rank') {
          state.sort = (state.sort === 'rank-asc') ? 'rank-desc' : 'rank-asc';
        } else if (key === 'name') {
          state.sort = 'name';
        } else if (key === 'score') {
          state.sort = 'score-desc';
        } else if (key === 'ciwg') {
          state.sort = 'ciwg-count';
        } else if (key === 'noncw') {
          state.sort = 'noncw-count';
        } else if (key === 'best-ciwg') {
          state.sort = 'best-ciwg';
        } else if (key === 'best-noncw') {
          state.sort = 'best-noncw';
        }
        if (sortSel) sortSel.value = state.sort;
        render();
      });
    });

    render();
  }
})();

;

